#!/usr/bin/env bash
# 08-secrets-export.sh - assemble peer-info + secrets bundle for offsite copy
#
# What it does:
#   1. verify SECRETS_DIR has expected contents (awg keys + xray uuid)
#   2. generate peer-info.txt (human-readable summary for the operator)
#   3. generate peer-info.json (machine-readable for tooling)
#   4. tar.gz the SECRETS_DIR  ->  /root/external-deploy-secrets.tar.gz
#   5. copy bundle to /home/$ADMIN_USER/ with admin ownership for scp pickup
#   6. print scp instructions + post-transfer wipe command
#
# This phase does NOT delete secrets. The user runs scripts/wipe-secrets.sh
# (or `sudo rm -rf $SECRETS_DIR` + remove tarball from admin home) after they
# have safely transferred the bundle to their workstation.

PHASE_ID="08-secrets-export"

run_phase() {
    load_state

    [ -n "${ADMIN_USER:-}"            ] || fail "ADMIN_USER not set"
    [ -n "${PUBLIC_IPV4:-}"           ] || fail "PUBLIC_IPV4 not set"
    [ -n "${AWG_LISTEN_PORT:-}"       ] || fail "AWG_LISTEN_PORT not set"
    [ -n "${AWG_PUB_EXTERNAL:-}"      ] || fail "AWG_PUB_EXTERNAL not set"
    [ -n "${XRAY_INBOUND_LISTEN:-}"   ] || fail "XRAY_INBOUND_LISTEN not set"
    [ -n "${XRAY_INBOUND_PORT:-}"     ] || fail "XRAY_INBOUND_PORT not set"
    [ -n "${XRAY_CLIENT_UUID:-}"      ] || fail "XRAY_CLIENT_UUID not set"

    backup_init "$PHASE_ID"
    backup_dir_recursive "${SECRETS_DIR:-/root/external-deploy-secrets}"
    ok "backup taken"

    local secdir="${SECRETS_DIR:-/root/external-deploy-secrets}"

    # ----------------------------------------------------------------
    # 1. Verify SECRETS_DIR contents
    # ----------------------------------------------------------------
    log "1/6 verify secrets present"
    [ -d "$secdir" ] || fail "secrets dir missing: $secdir"
    [ -s "${secdir}/awg_priv_external" ] || fail "missing: ${secdir}/awg_priv_external"
    [ -s "${secdir}/awg_pub_external"  ] || fail "missing: ${secdir}/awg_pub_external"
    [ -s "${secdir}/xray_client_uuid"  ] || fail "missing: ${secdir}/xray_client_uuid"
    ok "all expected secrets present"

    # ----------------------------------------------------------------
    # 2. Generate peer-info.txt (human readable)
    # ----------------------------------------------------------------
    log "2/6 generate peer-info.txt"

    local endpoint_v4="${PUBLIC_IPV4}:${AWG_LISTEN_PORT}"
    local endpoint_v6=""
    if [ -n "${PUBLIC_IPV6:-}" ]; then
        endpoint_v6="[${PUBLIC_IPV6}]:${AWG_LISTEN_PORT}"
    fi

    local now_iso
    now_iso=$(date -u +'%Y-%m-%dT%H:%M:%SZ')

    cat > "${secdir}/peer-info.txt" <<EOF
================================================================
External-node peer-info — generated by deploy-kit
================================================================
Generated: ${now_iso}
Hostname:  ${NODE_HOSTNAME:-$(hostname)}
Node ID:   ${NODE_ID:-<unset>}
RUN_ID:    ${RUN_ID}

----------------------------------------------------------------
AWG endpoint (use ONE of these as Endpoint= on the peer side)
----------------------------------------------------------------
  IPv4:    ${endpoint_v4}
  IPv6:    ${endpoint_v6:-<not configured>}

  PublicKey:           ${AWG_PUB_EXTERNAL}

  Obfuscation params (must match on the peer side):
    Jc = ${AWG_OBFUSC_JC:-<missing>}
    Jmin = ${AWG_OBFUSC_JMIN:-<missing>}
    Jmax = ${AWG_OBFUSC_JMAX:-<missing>}
    S1 = ${AWG_OBFUSC_S1:-<missing>}
    S2 = ${AWG_OBFUSC_S2:-<missing>}
    H1 = ${AWG_OBFUSC_H1:-<missing>}
    H2 = ${AWG_OBFUSC_H2:-<missing>}
    H3 = ${AWG_OBFUSC_H3:-<missing>}
    H4 = ${AWG_OBFUSC_H4:-<missing>}

----------------------------------------------------------------
xray inbound (peer's outbound config)
----------------------------------------------------------------
  Address:   ${XRAY_INBOUND_LISTEN}    (over AWG, NOT public)
  Port:      ${XRAY_INBOUND_PORT}
  Protocol:  vless
  Transport: tcp
  UUID:      ${XRAY_CLIENT_UUID}
  Level:     0

  Sample peer-side outbound (xray JSON):
    {
      "tag": "external-fi-${NODE_ID:-1}",
      "protocol": "vless",
      "settings": {
        "vnext": [{
          "address": "${XRAY_INBOUND_LISTEN}",
          "port": ${XRAY_INBOUND_PORT},
          "users": [{
            "id": "${XRAY_CLIENT_UUID}",
            "level": 0,
            "encryption": "none"
          }]
        }]
      },
      "streamSettings": { "network": "tcp" }
    }

----------------------------------------------------------------
To register an internal peer ON this external node, run:
----------------------------------------------------------------
  sudo /opt/deploy-kit/external/scripts/add-peer.sh \\
      --pubkey  '<INTERNAL_PUBLIC_KEY>' \\
      --allowed 'fd10::2/128'

  Replace <INTERNAL_PUBLIC_KEY> with the public key from internal node:
    awg show awg0 public-key
================================================================
EOF
    chmod 600 "${secdir}/peer-info.txt"
    ok "peer-info.txt written"

    # ----------------------------------------------------------------
    # 3. Generate peer-info.json (machine readable)
    # ----------------------------------------------------------------
    log "3/6 generate peer-info.json"
    require_command jq

    jq -n \
        --arg generated   "$now_iso" \
        --arg run_id      "${RUN_ID}" \
        --arg hostname    "${NODE_HOSTNAME:-$(hostname)}" \
        --arg node_id     "${NODE_ID:-}" \
        --arg ipv4        "${endpoint_v4}" \
        --arg ipv6        "${endpoint_v6}" \
        --arg awg_pub     "${AWG_PUB_EXTERNAL}" \
        --arg awg_jc      "${AWG_OBFUSC_JC:-}"   --arg awg_jmin "${AWG_OBFUSC_JMIN:-}" \
        --arg awg_jmax    "${AWG_OBFUSC_JMAX:-}" --arg awg_s1   "${AWG_OBFUSC_S1:-}"   \
        --arg awg_s2      "${AWG_OBFUSC_S2:-}"   --arg awg_h1   "${AWG_OBFUSC_H1:-}"   \
        --arg awg_h2      "${AWG_OBFUSC_H2:-}"   --arg awg_h3   "${AWG_OBFUSC_H3:-}"   \
        --arg awg_h4      "${AWG_OBFUSC_H4:-}" \
        --arg xray_listen "${XRAY_INBOUND_LISTEN}" \
        --arg xray_port   "${XRAY_INBOUND_PORT}" \
        --arg xray_uuid   "${XRAY_CLIENT_UUID}" \
        '{
            generated: $generated,
            run_id:    $run_id,
            hostname:  $hostname,
            node_id:   $node_id,
            awg: {
                endpoint_ipv4: $ipv4,
                endpoint_ipv6: $ipv6,
                public_key:    $awg_pub,
                obfuscation: {
                    jc: ($awg_jc|tonumber? // null),
                    jmin: ($awg_jmin|tonumber? // null),
                    jmax: ($awg_jmax|tonumber? // null),
                    s1: ($awg_s1|tonumber? // null),
                    s2: ($awg_s2|tonumber? // null),
                    h1: ($awg_h1|tonumber? // null),
                    h2: ($awg_h2|tonumber? // null),
                    h3: ($awg_h3|tonumber? // null),
                    h4: ($awg_h4|tonumber? // null)
                }
            },
            xray: {
                inbound: {
                    listen:   $xray_listen,
                    port:     ($xray_port|tonumber? // null),
                    protocol: "vless",
                    transport: "tcp",
                    uuid:     $xray_uuid,
                    level:    0
                }
            }
         }' \
        > "${secdir}/peer-info.json"
    chmod 600 "${secdir}/peer-info.json"
    ok "peer-info.json written"

    # ----------------------------------------------------------------
    # 4. Create tarball
    # ----------------------------------------------------------------
    log "4/6 create tarball"
    local tarball="/root/external-deploy-secrets-${RUN_ID}.tar.gz"
    secrets_export_bundle "$tarball"
    # secrets_export_bundle already prints "OK: secrets bundle: ..."

    # ----------------------------------------------------------------
    # 5. Copy to admin home for scp pickup
    # ----------------------------------------------------------------
    log "5/6 stage in admin home for scp"
    local admin_home
    admin_home=$(getent passwd "$ADMIN_USER" | cut -d: -f6)
    [ -d "$admin_home" ] || fail "admin home '$admin_home' does not exist"

    local stage="${admin_home}/external-deploy-secrets-${RUN_ID}.tar.gz"
    cp "$tarball" "$stage"
    chown "$ADMIN_USER:$ADMIN_USER" "$stage"
    chmod 600 "$stage"
    ok "staged: $stage"

    # ----------------------------------------------------------------
    # 6. Print instructions
    # ----------------------------------------------------------------
    log "6/6 instructions"
    echo
    step "How to retrieve and clean up secrets"

    cat <<EOF

  1. Download the bundle to your workstation:

       scp ${ADMIN_USER}@${PUBLIC_IPV4}:${stage} ./external-deploy-secrets-${RUN_ID}.tar.gz

  2. Inspect contents on your workstation (private keys included):

       tar -tzf external-deploy-secrets-${RUN_ID}.tar.gz

     You will find:
       - awg_priv_external   (AmneziaWG private key — KEEP SAFE)
       - awg_pub_external    (AmneziaWG public key — share with peer)
       - xray_client_uuid    (xray VLESS UUID — share with peer)
       - peer-info.txt       (human-readable summary)
       - peer-info.json      (machine-readable summary)

  3. After successful transfer, wipe secrets from the server:

       sudo rm -f ${stage}
       sudo rm -f ${tarball}
       sudo rm -rf ${secdir}

     (Only after you have verified the bundle is on your workstation!
      The private key cannot be recovered from this machine afterwards.
      The interface keeps working using the in-memory key as long as awg-quick
      keeps it; do NOT 'awg-quick down awg0' until you are sure.)

EOF

    log_file "[$PHASE_ID] secrets bundle: $stage"
    log_file "[$PHASE_ID] AWG_PUB_EXTERNAL=$AWG_PUB_EXTERNAL"
    log_file "[$PHASE_ID] XRAY_CLIENT_UUID=$XRAY_CLIENT_UUID"

    return 0
}